from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

# Database connection parameters
DB_HOST = "localhost"
DB_NAME = "your_database_name"
DB_USER = "your_username"
DB_PASS = "your_password"

def get_db_connection():
    conn = psycopg2.connect(
        host=DB_HOST,
        database=DB_NAME,
        user=DB_USER,
        password=DB_PASS
    )
    return conn

@app.route('/query', methods=['POST'])
def query_database():
    data = request.get_json()
    
    table_name = data.get('table')
    columns = data.get('columns', '*')
    filters = data.get('filters', [])
    
    if not table_name:
        return jsonify({'error': 'Table name is required'}), 400
    
    query_builder = f"SELECT {', '.join(columns)} FROM {table_name}"
    
    conditions = []
    for filter in filters:
        column = filter['column']
        value = filter['value']
        operator = filter.get('operator', '=')
        
        if operator not in ['=', '!=', '<', '>', '<=', '>=']:
            return jsonify({'error': f'Invalid operator: {operator}'}), 400
        
        conditions.append(f"{column} {operator} %s")
    
    if conditions:
        query_builder += " WHERE " + " AND ".join(conditions)
    
    try:
        conn = get_db_connection()
        cur = conn.cursor()
        
        # Execute the query with parameterized inputs to prevent SQL injection
        cur.execute(query_builder, [f['value'] for f in filters])
        
        rows = cur.fetchall()
        
        column_names = [desc[0] for desc in cur.description]
        result = [dict(zip(column_names, row)) for row in rows]
        
        cur.close()
        conn.close()
        
        return jsonify(result), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)